#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int A,B,C; scanf("%d %d %d", &A, &B, &C);
        if(A+B>=70 && A+C>=70 && B+C>=70) printf("PASS\n");
        else printf("FAIL\n");
    }
    return 0;
}

